+func TestResourceCollector_CollectVMDirs_EmptyDir(t *testing.T) {
+	tmpDir := t.TempDir()
+
+	rc := &ResourceCollector{
+		cfg:     config.DefaultConfig(),
+		vmDir:   tmpDir,
+		taskIDs: make(map[string]string),
+	}
+
+	rc.collectVMDirs()
+
